What does this print?

from abc import ABC, abstractmethod

class Shape(ABC):
    @abstractmethod
    def area(self) -> float: ...

class Circle(Shape):
    pass

try:
    c = Circle()
except Exception as e:
    print(type(e).__name__)

Which statement about Protocol is true?

from typing import Protocol

class Drawable(Protocol):
    def draw(self) -> None: ...

class Canvas:
    def draw(self) -> None:
        print('drawing')

def render(obj: Drawable) -> None:
    obj.draw()

render(Canvas())

What does this print?

class A:
    def greet(self):
        print('A')

class B(A):
    def greet(self):
        print('B')
        super().greet()

class C(A):
    def greet(self):
        print('C')
        super().greet()

class D(B, C):
    def greet(self):
        print('D')
        super().greet()

D().greet()
